document.addEventListener("DOMContentLoaded",function(){const yearSpan=document.getElementById("year");const currentYear=new Date().getFullYear();yearSpan.textContent=currentYear;console.log("Website loaded successfully!")});window.addEventListener('scroll',function(){let scrolled=this.window.scrollY;let speedMultiplier=0.5;this.document.body.style.backgroundPositionY=(scrolled*speedMultiplier)+'px'});const revealObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('is-visible');observer.unobserve(entry.target)}})},{threshold:0.15});const hiddenSections=document.querySelectorAll('.scroll-reveal');hiddenSections.forEach((section)=>{revealObserver.observe(section)});document.addEventListener('DOMContentLoaded',()=>{const emailLink=document.querySelector('.contact-icon.email-link');const copyMessage=document.querySelector('.copy-message');if(emailLink&&copyMessage){emailLink.addEventListener('click',function(e){e.preventDefault();const email=this.getAttribute('data-email');navigator.clipboard.writeText(email).then(()=>{copyMessage.classList.add('show');setTimeout(()=>{copyMessage.classList.remove('show')},2500)}).catch(err=>{console.error('Failed to copy email: ',err)})})}
const queryString=window.location.search;let targetPath="home";if(queryString){targetPath=queryString.substring(1);window.history.replaceState(null,'',`/${targetPath}`)}
document.querySelectorAll('.page-section').forEach(page=>{page.classList.remove('active-page')});const initialPage=document.getElementById(`page-${targetPath}`);if(initialPage){initialPage.classList.add('active-page');if(typeof resetRevealAnimations==='function'){resetRevealAnimations(initialPage)}}
document.querySelectorAll('.nav-tab').forEach(tab=>{tab.classList.remove('active');if(tab.getAttribute('data-target')===`page-${targetPath}`){tab.classList.add('active')}});const navTabs=document.querySelectorAll('.nav-tab');const pageSections=document.querySelectorAll('.page-section');navTabs.forEach(tab=>{tab.addEventListener('click',function(e){e.preventDefault();const targetId=this.getAttribute('data-target');const targetPage=document.getElementById(targetId);const currentPage=document.querySelector('.page-section.active-page');if(currentPage===targetPage)return;document.querySelector('.nav-tab.active').classList.remove('active');this.classList.add('active');const urlPath=targetId.replace('page-','');window.history.pushState(null,'',`/${urlPath}`);window.scrollTo({top:0,behavior:'smooth'});currentPage.classList.add('fading-out');setTimeout(()=>{currentPage.classList.remove('active-page','fading-out');targetPage.classList.add('active-page');resetRevealAnimations(targetPage)},450)})});function resetRevealAnimations(page){const reveals=page.querySelectorAll('.scroll-reveal');reveals.forEach(el=>{el.classList.remove('is-visible');if(typeof revealObserver!=='undefined'){revealObserver.observe(el)}})}
const courseTiles=document.querySelectorAll('.course-tile');courseTiles.forEach(tile=>{tile.addEventListener('click',function(e){const isAlreadyOpen=this.classList.contains('touch-open');courseTiles.forEach(t=>t.classList.remove('touch-open'));if(!isAlreadyOpen){this.classList.add('touch-open')}
e.stopPropagation()})});document.addEventListener('click',function(){courseTiles.forEach(t=>t.classList.remove('touch-open'))});const deepLinks=document.querySelectorAll('.deep-link');deepLinks.forEach(link=>{link.addEventListener('click',function(e){e.preventDefault();const targetPageId=this.getAttribute('data-target-page');const targetElementId=this.getAttribute('data-target-id');const targetPage=document.getElementById(targetPageId);const currentPage=document.querySelector('.page-section.active-page');if(currentPage!==targetPage){const targetTab=document.querySelector(`.nav-tab[data-target="${targetPageId}"]`);if(targetTab)targetTab.click();}
setTimeout(()=>{const targetElement=document.getElementById(targetElementId);if(targetElement){targetElement.scrollIntoView({behavior:'smooth',block:'center'});targetElement.classList.add('target-highlight');setTimeout(()=>{targetElement.classList.remove('target-highlight')},2000)}},500)})})})